function userLogin() {
  // Read username
  var username = document.login.username.value.trim();
  if (!username) {
    document.getElementById('error').innerText = 'يرجى إدخال اسم المستخدم';
    showErrorPopup();
    animating = false;
    return;
  }
  
  // Read selected speed from radio buttons named "domain"
  var speedValue = '';
  var radios = document.getElementsByName('domain');
  for (var i = 0; i < radios.length; i++) {
    if (radios[i].checked) {
      speedValue = radios[i].value;
      break;
    }
  }
  if (!speedValue) {
    document.getElementById('error-msg').style.display = 'block';
    animating = false;
    return;
  }
  
  // Password is empty (as per original logic)
  var password = '';
  
  // Read update checkbox (if exists)
  var chupdate = document.getElementById('chupdate');
  var updateVal = chupdate && chupdate.checked ? '' : '_Uoff';
  
  // Call Ulogin with username, password, speed + update
  Ulogin(username, password, speedValue + updateVal);
}

