    // --- QR scanner (robust start/stop) ---
    (function () {
      var readerId = "reader";
      var modal = $id('scanner-modal');
      var startBtn = $id('start-scan');
      var closeBtn = $id('close-scan');

      var qrConfig = { fps: 10, qrbox: { width: 250, height: 250 } };

      function createScannerIfNeeded() {
        if (html5QrCodeInstance) return html5QrCodeInstance;
        if (typeof Html5Qrcode === 'undefined') return null;
        try {
          html5QrCodeInstance = new Html5Qrcode(readerId);
          return html5QrCodeInstance;
        } catch (err) {
          console.warn('Html5Qrcode init failed:', err);
          html5QrCodeInstance = null;
          return null;
        }
      }

      async function stopScanner() {
        if (!html5QrCodeInstance) {
          if (modal) modal.style.display = 'none';
          return;
        }
        try {
          await html5QrCodeInstance.stop();
          try { html5QrCodeInstance.clear(); } catch (e) {}
        } catch (err) {
          console.warn('Error stopping scanner:', err);
        } finally {
          if (modal) modal.style.display = 'none';
        }
      }

      async function startScanner() {
        var scanner = createScannerIfNeeded();
        if (!scanner) {
          console.error('Html5Qrcode not available or reader element missing.');
          return;
        }
        if (modal) modal.style.display = 'flex';
        try {
          await scanner.start(
            { facingMode: "environment" },
            qrConfig,
            function (decodedText) {
              try { alert("Scanned: " + decodedText); } catch (e) {}
              stopScanner();
            },
            function (errorMessage) {
              // optional decode error handling
            }
          );
        } catch (err) {
          console.error('Camera start error:', err);
          if (modal) modal.style.display = 'none';
        }
      }

      if (startBtn) startBtn.addEventListener('click', function (e) {
        e.stopPropagation();
        startScanner();
      });

      if (closeBtn) closeBtn.addEventListener('click', function (e) {
        e.stopPropagation();
        stopScanner();
      });

      // Close modal by clicking outside reader area
      if (modal) {
        modal.addEventListener('click', function (ev) {
          if (ev.target === modal) stopScanner();
        });
      }
    })();

    // --- Flickity carousel + dot/radio sync (guarded) ---
    // --- Flickity <-> custom dots (radios) sync (drop-in replacement) ---
  (function () {
    var elem = document.querySelector('.ht-main-csl');
    if (!elem) return;
  
    // Try to get an existing Flickity instance (if initialized via data-flickity)
    var flkty = (window.Flickity && Flickity.data && Flickity.data(elem)) || null;
  
    // If no instance yet, create one using the data-flickity attribute (if present)
    if (!flkty && window.Flickity) {
      var opts = {};
      try {
        var raw = elem.getAttribute('data-flickity') || '{}';
        opts = JSON.parse(raw);
      } catch (err) {
        opts = {};
      }
      flkty = new Flickity(elem, opts);
    }
  
    if (!flkty) return;
  
    // Your custom dot/radio inputs
    var radios = Array.from(document.querySelectorAll('.ht-cekb'));
  
    // Helper: safely set radio checked state
    function setActiveRadio(index) {
      if (!radios.length) return;
      radios.forEach(function (r) { r.checked = false; });
      if (typeof index === 'number' && radios[index]) radios[index].checked = true;
    }
  
    // When a radio changes (user clicked a dot/label), select the corresponding slide
    radios.forEach(function (r, i) {
      r.removeEventListener('change', radioChangeHandler);
      r.addEventListener('change', radioChangeHandler);
      function radioChangeHandler() {
        if (!this.checked) return;
        if (flkty && typeof flkty.select === 'function') {
          flkty.select(i);
        }
      }
    });
  
    // When Flickity changes slide, update the radios
    // Use 'select.flickity' event (Flickity emits 'select' on the instance)
    try {
      flkty.on('select', function () {
        var idx = flkty.selectedIndex;
        setActiveRadio(idx);
      });
    } catch (err) {
      // fallback: poll selectedIndex once if event binding fails
      console.warn('Flickity select binding failed, falling back to initial sync.', err);
    }
  
    // Initial sync (in case carousel already moved)
    setActiveRadio(typeof flkty.selectedIndex === 'number' ? flkty.selectedIndex : 0);
  
    // Optional: if you want clicking labels (not only radios) to also force select,
    // ensure labels are associated with inputs (for="...") — the radio change handler covers that.
  })();

