// --- WhatsApp dialog: safe, robust wiring and redirect function ---
(function () {
  function $id(id) { return document.getElementById(id); }
  function $qs(sel) { return document.querySelector(sel); }
  function $qsa(sel) { return Array.prototype.slice.call(document.querySelectorAll(sel)); }

  function initWhatsApp() {
    var toggleBtn = $id("wa-toggle-btn");
    var closeBtn = $id("x-btn");
    var waDialog = $qs(".wa-dialog");
    var adminBtns = $qsa('.wa-admin-btn'); // NodeList -> Array
    var waTextEl = $id("wa-text");

    // Toggle open/close
    if (toggleBtn && waDialog) {
      // Use a single handler and ensure it toggles display reliably
      toggleBtn.removeEventListener("click", waToggleHandler);
      toggleBtn.addEventListener("click", waToggleHandler);
    }

    // Close button
    if (closeBtn && waDialog) {
      closeBtn.removeEventListener("click", waCloseHandler);
      closeBtn.addEventListener("click", waCloseHandler);
    }

    // Admin buttons selection (delegation safe)
    if (adminBtns && adminBtns.length) {
      adminBtns.forEach(function (btn) {
        btn.removeEventListener('click', adminBtnClick);
        btn.addEventListener('click', adminBtnClick);
      });
    }

    // Ensure clicking outside the dialog closes it (optional)
    document.removeEventListener('click', outsideWaClick);
    document.addEventListener('click', outsideWaClick);

    // Handler implementations
    function waToggleHandler(e) {
      e && e.stopPropagation && e.stopPropagation();
      if (!waDialog) return;
      waDialog.classList.toggle("open");
    }

    function waCloseHandler(e) {
      e && e.stopPropagation && e.stopPropagation();
      if (!waDialog) return;
      waDialog.classList.remove("open");
    }

    function adminBtnClick(e) {
      // remove active from all, add to clicked
      var btns = document.querySelectorAll('.wa-admin-btn');
      btns.forEach(function (b) { b.classList.remove('active'); });
      this.classList.add('active');
    }

    function outsideWaClick(e) {
      if (!waDialog) return;
      if (waDialog.classList.contains("open") && !waDialog.contains(e.target) && !toggleBtn.contains(e.target)) {
        waDialog.classList.remove("open");
      }
    }

    // Expose redirectTowa globally (override safely)
    window.redirectTowa = function () {
      try {
        var userAgent = navigator.userAgent || navigator.vendor || window.opera;
        var activeBtn = document.querySelector('.wa-admin-btn.active');
        var phoneNumber = activeBtn ? activeBtn.getAttribute('data-phone') : null;
        // fallback phone if none selected
        if (!phoneNumber) phoneNumber = "905413646996";

        // Normalize phone: remove spaces, plus signs, parentheses, dashes
        phoneNumber = phoneNumber.replace(/[\s()+-]/g, "");

        var message = waTextEl ? waTextEl.value : "";
        message = encodeURIComponent(message || "");

        // Prefer whatsapp:// on mobile; use web.whatsapp.com on desktop
        var isMobile = /android|iphone|ipad|ipod/i.test(userAgent);
        var url;
        if (isMobile) {
          // Use the official whatsapp scheme
          url = "whatsapp://send?phone=" + phoneNumber + "&text=" + message;
        } else {
          // Use web.whatsapp.com for desktop browsers
          url = "https://web.whatsapp.com/send?phone=" + phoneNumber + "&text=" + message;
        }

        // Open in a new tab/window
        window.open(url, "_blank");
      } catch (err) {
        console.error("redirectTowa error:", err);
      }
    };
  }

  // Run on DOM ready
  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", initWhatsApp);
  } else {
    initWhatsApp();
  }
})();



// clock
// 1. Get the hidden MikroTik time (assumed to be in seconds)
const rawValue = document.querySelector('[count-down-span]').innerText;
let totalSeconds = parseInt(rawValue) || 0;

function updateMikroTikCountdown() {
  if (totalSeconds <= 0) {
    // When unblocked: Refresh the page or redirect
    window.location.reload(); 
    return;
  }

  // Convert seconds to D:H:M:S
  const d = Math.floor(totalSeconds / (3600 * 24));
  const h = Math.floor((totalSeconds % (3600 * 24)) / 3600);
  const m = Math.floor((totalSeconds % 3600) / 60);
  const s = totalSeconds % 60;

  const format = n => n < 10 ? `0${n}` : n;

  // Update UI
  document.getElementById('days').textContent = format(d);
  document.getElementById('hours').textContent = format(h);
  document.getElementById('minutes').textContent = format(m);
  
  const secEl = document.getElementById('seconds');
  const formattedSec = format(s);

  // Smooth Tick & Animation
  if (secEl.textContent !== String(formattedSec)) {
    secEl.textContent = formattedSec;
    secEl.classList.remove('pulse-active');
    void secEl.offsetWidth; // Force reflow
    secEl.classList.add('pulse-active');
  }

  totalSeconds--;
}

// Start the loop
if (totalSeconds > 0) {
  setInterval(updateMikroTikCountdown, 1000);
  updateMikroTikCountdown();
} else {
  // If no time is found, default to 00
  document.querySelectorAll('.segment-value').forEach(el => el.textContent = "00");
}

