const Confirm = {
    open(opt) {
        const html = `
            <div class="confirm">
                <div class="confirm__window">
                    <div class="confirm__titlebar">${opt.title}</div>
                    <div class="confirm__content">${opt.msg}</div>
                    <div class="confirm__buttons">
                        <button class="confirm__btn" id="c_can">إلغاء</button>
                        <button class="confirm__btn confirm__btn--ok" id="c_ok">تأكيد</button>
                    </div>
                </div>
            </div>`;
        document.body.insertAdjacentHTML('beforeend', html);
        const el = document.querySelector('.confirm');
        document.getElementById('c_ok').onclick = () => { opt.onok(); el.remove(); };
        document.getElementById('c_can').onclick = () => el.remove();
    }
};

