// speed update toggle

let isOpen = false;
const menu = document.getElementById("spdtgl-menu");
const plusIcon = document.getElementById("plus");
const speedsContainer = document.querySelector(".speeds");
const speedText = document.getElementById("sspeed");
const speedSelect = document.getElementById("speedchange");

function expand(event) {
  if (event) event.stopPropagation();
  
  if (!isOpen) {
    speedsContainer.classList.add("expanded");
    menu.style.transform = "scale(2)";
    isOpen = true;
  } else {
    speedsContainer.classList.remove("expanded");
    menu.style.transform = "scale(0)";
    isOpen = false;
  }
}

function setSpeed(name, value) {
  speedText.innerText = name;
  speedSelect.value = value;
  speedSelect.dispatchEvent(new Event("change"));
  setTimeout(expand, 300);
}

document.addEventListener("click", (e) => {
  if (isOpen && !menu.contains(e.target)) expand();
});

